#include "envoy/registry/registry.h"
#include "envoy/server/filter_config.h"

#include "source/extensions/filters/http/common/factory_base.h"

#include "pass_through_filter.h"

#include "google/protobuf/empty.pb.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThrough {

/**
 * Config factory for the pass-through HTTP decoder filter.
 * Follows the NamedHttpFilterConfigFactory pattern used throughout Envoy's
 * source/extensions/filters/http/ directory.
 */
class PassThroughFilterFactory
    : public Common::FactoryBase<Envoy::ProtobufWkt::Empty> {
public:
  PassThroughFilterFactory() : FactoryBase("envoy.filters.http.pass_through") {}

private:
  Http::FilterFactoryCb createFilterFactoryFromProtoTyped(
      const Envoy::ProtobufWkt::Empty& /*proto_config*/,
      const std::string& /*stats_prefix*/,
      Server::Configuration::FactoryContext& /*context*/) override {
    return [](Http::FilterChainFactoryCallbacks& callbacks) -> void {
      callbacks.addStreamDecoderFilter(std::make_shared<PassThroughFilter>());
    };
  }
};

/**
 * Static registration for the pass-through filter. @see RegisterFactory.
 */
REGISTER_FACTORY(PassThroughFilterFactory, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace PassThrough
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

